import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { doctorAPI } from '../services/api';
import { getErrorMessage } from '../utils/helpers';
import DoctorCard from '../components/DoctorCard';
import './DashboardPages.css';

const AdminPage = ({ showToast }) => {
  const [doctors, setDoctors] = useState([]);
  const [pendingDoctors, setPendingDoctors] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('all');
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  useEffect(() => {
    loadDoctors();
    loadPendingDoctors();
  }, []);

  const loadDoctors = async () => {
    setLoading(true);
    try {
      const data = await doctorAPI.getAdminAll();
      setDoctors(data);
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    } finally {
      setLoading(false);
    }
  };

  const loadPendingDoctors = async () => {
    try {
      const data = await doctorAPI.getPending();
      setPendingDoctors(data);
    } catch (error) {
      console.error(error);
    }
  };

  const handleApprove = async (doctorId) => {
    try {
      await doctorAPI.approve(doctorId);
      showToast('Doctor approved successfully!', 'success');
      loadDoctors();
      loadPendingDoctors();
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    }
  };

  const handleReject = async (doctorId) => {
    const reason = window.prompt('Reason for rejection (optional):');
    if (reason !== null) {
      try {
        await doctorAPI.reject(doctorId, reason);
        showToast('Doctor rejected successfully!', 'success');
        loadDoctors();
        loadPendingDoctors();
      } catch (error) {
        showToast(getErrorMessage(error), 'error');
      }
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="dashboard-page">
      <header className="header">
        <div className="header-content">
          <h1>Admin Dashboard</h1>
          <div className="header-right">
            <div className="user-info">
              Logged in as <strong>{user?.name}</strong> ({user?.role})
            </div>
            <button className="logout-btn" onClick={handleLogout}>
              Logout
            </button>
          </div>
        </div>
      </header>

      <div className="container">
        <div className="page-content">
          <div className="tabs">
            <button
              className={`tab-btn ${activeTab === 'all' ? 'active' : ''}`}
              onClick={() => setActiveTab('all')}
            >
              All Doctors ({doctors.length})
            </button>
            <button
              className={`tab-btn ${activeTab === 'pending' ? 'active' : ''}`}
              onClick={() => setActiveTab('pending')}
            >
              Pending Approval ({pendingDoctors.length})
            </button>
          </div>

          {loading ? (
            <div className="loading">Loading...</div>
          ) : (
            <>
              {activeTab === 'all' && (
                <div className="section">
                  <h2>All Doctors</h2>
                  {doctors.length === 0 ? (
                    <div className="no-data">No doctors found</div>
                  ) : (
                    <div className="doctors-list">
                      {doctors.map((doctor) => (
                        <DoctorCard
                          key={doctor.id}
                          doctor={doctor}
                          isAdmin={true}
                          showApprovalStatus={true}
                          onApprove={handleApprove}
                          onReject={handleReject}
                        />
                      ))}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'pending' && (
                <div className="section">
                  <h2>Pending Doctor Approvals</h2>
                  {pendingDoctors.length === 0 ? (
                    <div className="no-data">No pending approvals</div>
                  ) : (
                    <div className="doctors-list">
                      {pendingDoctors.map((doctor) => (
                        <DoctorCard
                          key={doctor.id}
                          doctor={doctor}
                          isAdmin={true}
                          onApprove={handleApprove}
                          onReject={handleReject}
                        />
                      ))}
                    </div>
                  )}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
